head.script:
// 세션정보 가져오기
scwin.sUserId  = $c.data.getMemInfo("userId"); 
scwin.sUserClsCd = $c.data.getMemInfo("userClsCd"); 
scwin.sClntNo  = $c.data.getMemInfo("clntNo"); 
scwin.sClntNm  = $c.data.getMemInfo("clntNm"); 
scwin.sLobranCd = $c.data.getMemInfo("loUpperLobranCd"); 
scwin.sSysAdminYn = $c.data.getMemInfo("sysAdminYn"); 

scwin.strFromDate = $c.date.getServerDateTime();
scwin.strToDate = $c.date.getServerDateTime();      
scwin.strDate = scwin.strFromDate;
scwin.strTomorrow = $c.date.addDate(scwin.strFromDate, 1); // 익일


// hidden
scwin.vehclNoCd = "";
scwin.cheCnt = "";

scwin.DELETE_AUTH = $p.top().scwin.globalVal.DELETE_AUTH;
scwin.CREATE_AUTH = $p.top().scwin.globalVal.CREATE_AUTH;
scwin.PRINT_AUTH = $p.top().scwin.globalVal.PRINT_AUTH;

scwin.onpageload = function() {
    scwin.sUserId  = $c.data.getMemInfo("userId"); 
    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd"); 
    scwin.sClntNo  = $c.data.getMemInfo("clntNo"); 
    scwin.sClntNm  = $c.data.getMemInfo("clntNm"); 
    scwin.sLobranCd = $c.data.getMemInfo("loUpperLobranCd") == null ? "" : $c.data.getMemInfo("loUpperLobranCd") ; 
    scwin.sSysAdminYn = $c.data.getMemInfo("sysAdminYn");

    const codeOptions = [
        {grpCd: "OP190", compID: "acb_workGubun"}  
      , {grpCd: "OP101", compID: "acb_cntrSizCd"}  
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function() {
    let e = "";

    scwin.sUserId  = $c.data.getMemInfo("userId"); 
    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd"); 
    scwin.sClntNo  = $c.data.getMemInfo("clntNo"); 
    scwin.sClntNm  = $c.data.getMemInfo("clntNm"); 
    scwin.sLobranCd = $c.data.getMemInfo("loUpperLobranCd") == null ? "" : $c.data.getMemInfo("loUpperLobranCd") ; 
    scwin.sSysAdminYn = $c.data.getMemInfo("sysAdminYn"); 

    wrkStDt.setValue(scwin.strDate);
    wrkEndDt.setValue(scwin.strDate);

    // 점소 조회
    e = await $c.sbm.execute(sbm_joblevel);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_joblevel_submitdone(e);
    }

    e = await $c.sbm.execute(sbm_dcScKnd);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_dcScKnd_submitdone(e);
    }



    if (scwin.DELETE_AUTH == "") {
        $c.gus.cfDisableBtn([btn_Del]);
    }
    if (scwin.CREATE_AUTH == "") {
        $c.gus.cfDisableBtn([btn_Add]);
    }
    if (scwin.PRINT_AUTH == "") {
        $c.gus.cfDisableBtn([btn_Dcsn, btn_DcsnChoice]);
    }
    // 작업구분 초기화
    acb_workGubun.setValue("C");
    scwin.f_createGrid();
    $c.gus.cfDisableObjects([ed_dptStDt, ed_dptEndDt, udc_dptDt]);
};

scwin.ondataload = function() {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_createGrid = function () {
    if (ds_emp.getCellData(0, "wrkCls") == "C" || acb_workGubun.getValue() == "C") {
        if (acb_logisticsBranch.getValue() == "6AA") { 
            gr_emp.show();  
            gr_emp2.hide(); 
            gr_emp3.hide(); 
            udc_section1.setGridId("gr_emp");
        } else {
            gr_emp.hide();  
            gr_emp2.show(); 
            gr_emp3.hide(); 
            udc_section1.setGridId("gr_emp2");
        }
    } else {
        gr_emp.hide();  
        gr_emp2.hide(); 
        gr_emp3.show(); 
        udc_section1.setGridId("gr_emp3");
    }
};

