// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
    }
};


scwin.f_Retrieve = async function() {
    const cntrBox = dma_input.get("cntrBox"); 
	if (cntrBox != "" && (ed_cntrNo.getValue() != "")) {
		await $c.gus.cfAlertMsg("컨테이너 다중검색의 경우 앞의 하얀 컨테이너박스의 내용을 삭제해주세요.");
		return;
	}

    scwin.f_createGrid();
    scwin.f_HeaderCreate();

 	$c.gus.cfEnableBtnOnly([btn_Dcsn, btn_DcsnChoice]);

    scwin.cheCnt = "0"

    acb_wrkClsCd.setValue(""); 
    acb_pusanClsCd.setValue(""); 

    let e = await $c.sbm.execute(sbm_retrieve);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieve_submitdone(e);
    }
};

// 헤더셋팅
scwin.f_HeaderCreate = function () {  
    ds_retrieve.removeAll(); 
    ds_retrieve.insertRow();
    ds_retrieve.setCellData(0, "regId", scwin.sUserId);
    ds_retrieve.setCellData(0, "lobran", acb_logisticsBranch.getValue());  // 점소
    ds_retrieve.setCellData(0, "wrkStDt", wrkStDt.getValue());
    ds_retrieve.setCellData(0, "wrkEndDt", wrkEndDt.getValue());
    ds_retrieve.setCellData(0, "cntrNo", ed_cntrNo.getValue());
    ds_retrieve.setCellData(0, "cntrBox", dma_input.get("cntrBox"));
    ds_retrieve.setCellData(0, "vehclNo", ed_vehclNo.getValue());
    ds_retrieve.setCellData(0, "odrNo", ed_odrNo.getValue());

    ds_retrieve.setCellData(0, "wrkCls", acb_workGubun.getValue());
    ds_retrieve.setCellData(0, "dcScKnd", acb_dcScKnd.getValue());
    ds_retrieve.setCellData(0, "dptWrkPlCd", ed_dptWrkPlCd.getValue());
    ds_retrieve.setCellData(0, "arvWrkPlCd", ed_arvWrkPlCd.getValue());
    ds_retrieve.setCellData(0, "bilgMchtCd", ed_bilgMchtCd.getValue());
    ds_retrieve.setCellData(0, "copCoCd", ed_copCoCd.getValue());
    ds_retrieve.setCellData(0, "selConfirm", acb_selConfirm.getValue());
    ds_retrieve.setCellData(0, "dcScRegId", ed_alloccarPicId.getValue());

    ds_retrieve.setCellData(0, "wrkClsCd", "");
    ds_retrieve.setCellData(0, "dcScAmtRate", ed_dcScAmtRate.getValue());
    ds_retrieve.setCellData(0, "cntrSizCd", acb_cntrSizCd.getValue());                
    ds_retrieve.setCellData(0, "lineCd", ed_lineCd.getValue());
    ds_retrieve.setCellData(0, "dtGubun", acb_dtGubun.getValue());
    ds_retrieve.setCellData(0, "dptStDt", ed_dptStDt.getValue());
    ds_retrieve.setCellData(0, "dptEndDt", ed_dptEndDt.getValue());                
    ds_retrieve.setCellData(0, "dptGubun", acb_dptGubun.getValue());
    ds_retrieve.setCellData(0, "reeferYn", acb_reeferYn.getValue());
};

scwin.f_Reset = function() {
    $c.gus.cfInitObjects(tb_searchCondition);

    acb_workGubun.setValue("B");
    wrkStDt.setValue(scwin.strDate);
    wrkEndDt.setValue(scwin.strDate);
};

// 등록
scwin.f_Register = async function () {
    var activeGrid = scwin.f_getActiveGrid();
    var k = 0;

    if (ds_emp.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }      

    if (scwin.CREATE_AUTH == "") {
        await $c.gus.cfAlertMsg("등록 권한이 없습니다.");
        return;
    }

    if (ica_allCopCoConfirmDt.getValue() != "") {
        if (!$c.gus.cfValidate([ica_allCopCoConfirmDt])) {
            return;
        }
    }

    for (var i = 0; i < ds_emp.getRowCount(); i++) {
        if (ds_emp.getCellData(i, "che") == 1) {
            k++;

            if (ds_emp.getCellData(i, "dcScNm") == "") { 
                ds_emp.setRowPosition(i);
                if (await $c.gus.cfAlertMsg((i+1) + "번째 등록이 되지 않았습니다. \n 할인할증사유를 먼저 선택 해주세요")) {
                    activeGrid.setFocusedCell(i, "dcScNm", true);
                    return ;
                }
            }

            if (ica_allCopCoConfirmDt.getValue().trimAll() != "") {
                ds_emp.setCellData(i, "regDtm", ica_allCopCoConfirmDt.getValue());
                ds_emp.setCellData(i, "confirmDt", ica_allCopCoConfirmDt.getValue());
            }
        } else {
            ds_emp.undoRow(i);
        }
    }

    if (k == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
        return;
    }

    // Grid의 필수 입력 항목에 대해서 Check 한다.
    if (!$c.gus.cfValidate([activeGrid])) {
        return;
    }

    let regChk = await $c.win.confirm(MSG_CM_CRM_002); 
    if (regChk) {
        scwin.f_HeaderCreate();

        $c.sbm.setAction(sbm_saveEmp, "/ds.op.wrkrslts.transwrkrslts.RegistSurchargeInformationCMD.do?pageGubun=1");
        let e = await $c.sbm.execute(sbm_saveEmp);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_saveEmp_submitdone(e);
        } 
    }
};

// 확정
scwin.f_Dcsn = async function() {
    if (ds_emp.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    var activeGrid = scwin.f_getActiveGrid();
    // Grid의 필수 입력 항목에 대해서 Check 한다.
    if (!$c.gus.cfValidate([activeGrid])) {
        return;
    }

    if (ica_allCopCoConfirmDt.getValue() != "") {
        if (!$c.gus.cfValidate([ica_allCopCoConfirmDt])) {
            return;
        }
    }

    var j = 0;
    for (var i = 0; i < ds_emp.getRowCount(); i++) {
        if (ds_emp.getCellData(i, "che") == "1") { 
            j++;
            if (ds_emp.getCellData(i, "dcsnDt") != "" && Number(ds_emp.getCellData(i, "regDtm")) > Number(ds_emp.getCellData(i, "dcsnDt"))) {
                ds_emp.setRowPosition(i);
                if (await $c.gus.cfAlertMsg("확정일자는 등록일자보다 빠를수 없습니다.")) {
                    activeGrid.setFocusedCell(i, "dcsnDt", true);
                    return;
                }
            }

            if (ica_allCopCoConfirmDt.getValue().trimAll() != "") {
                ds_emp.setCellData(i, "regDtm", ica_allCopCoConfirmDt.getValue());
            }

        } else {
            ds_emp.undoRow(i);
        }
    }

    if (j == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["Data"]);
        return;
    }

    let chk = await $c.win.confirm("확정하시겠습니까"); 
    if (chk) {
        scwin.f_HeaderCreate();

        $c.sbm.setAction(sbm_saveEmp, "/ds.op.wrkrslts.transwrkrslts.RegistSurchargeDecisionCMD.do?pageGubun=1");
        let e = await $c.sbm.execute(sbm_saveEmp);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_saveEmp_submitdone(e);
        } 
    }
};

scwin.f_toExcel1 = function () {
    var activeGrid = scwin.f_getActiveGrid();
    const options = {
        fileName: "오더 정보" + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        , sheetName: "오더 정보"
        , type : 1+4+8+16
    };

    const infoArr = [];

    $c.data.downloadGridViewExcel(activeGrid, options, infoArr);
};

scwin.f_Batch = async function() {
    var j = 0;
    if (acb_dcScKndBatch.getValue() == "") {
      await $c.gus.cfAlertMsg("일괄적용 할증종류가 선택 되지 않았습니다. \n 확인을 먼저 해주세요");
      return;
    }

    if (ed_aptPrice.getValue() == "" && ed_aptPercent.getValue() == "") {
      await $c.gus.cfAlertMsg("일괄적용할 적용금액 또는 할증률을 입력하세요.");
      return;
    }

    if (ed_aptPrice.getValue() != "") {
        for (var i = 0; i < ds_emp.getRowCount(); i++) {
            if (ds_emp.getCellData(i, "che") == 1) {
                j++;
                if (ds_emp.getCellData(i, "dcScCd") != "") {
                    continue;
                }
                ds_emp.setCellData(i, "dcScNm", acb_dcScKndBatch.getItem(acb_dcScKndBatch.getSelectedIndex()).orgLabel);
                ds_emp.setCellData(i, "dcScCd", acb_dcScKndBatch.getValue());
                ds_emp.setCellData(i, "dcScAmt", ed_aptPrice.getValue());
                ds_emp.setCellData(i, "dcScTotal", Number(ed_aptPrice.getValue()) + Number(ds_emp.getCellData(i, "dcScTotal")));
            }
        }
    } else if (ed_aptPercent.getValue() != "") {
        for (var i = 0; i < ds_emp.getRowCount(); i++) {
            if (ds_emp.getCellData(i, "che") == 1) {
                j++;
                if (ds_emp.getCellData(i, "dcScCd") != "") {
                    continue;
                }
                ds_emp.setCellData(i, "dcScNm", acb_dcScKndBatch.getItem(acb_dcScKndBatch.getSelectedIndex()).orgLabel);
                ds_emp.setCellData(i, "dcScCd", acb_dcScKndBatch.getValue());
                ds_emp.setCellData(i, "dcScAmt", Math.round(ds_emp.getCellData(i, "pchsAmt") * ed_aptPercent.getValue() * 0.01, 1));
                ds_emp.setCellData(i, "dcScTotal", Number(ed_aptPrice.getValue()) + Number(ds_emp.getCellData(i, "dcScTotal")));
            }
        }
    }

    if (j == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["Data"]); //alert("선택된 항목이없습니다.");
        return;
    }
};

// 할인할증자료 삭제
scwin.f_Delete = async function () {
    var icnt = 0;

    if (ds_emp.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]); 
        return;
    }

    if (scwin.DELETE_AUTH == "") {  
        await $c.gus.cfAlertMsg("삭제 권한이 없습니다.");
        return;
    }

    for (var i = 0; i < ds_emp.getRowCount(); i++) { 
        if (ds_emp.getCellData(i, "che") == 1) { 
            icnt++;
            if (ds_emp.getCellData(i,"dcsnYn") == 2 && ds_emp.getCellData(i,"dcsnDt").trim() != "") { 
                await $c.gus.cfAlertMsg("확정되었으므로 삭제할 수 없습니다.");
                return; 
            }   
        }
    }

    if (icnt > 0) { 
        let delChk = await $c.win.confirm("삭제하시겠습니까?"); 
        if (delChk) {
            ds_retrieve.removeAll();
            ds_retrieve.insertRow();
            ds_retrieve.setCellData(0, "lobran", acb_logisticsBranch.getValue());  // 점소
            ds_retrieve.setCellData(0, "wrkStDt", wrkStDt.getValue());
            ds_retrieve.setCellData(0, "wrkEndDt", wrkEndDt.getValue());
            ds_retrieve.setCellData(0, "cntrNo", ed_cntrNo.getValue());
            ds_retrieve.setCellData(0, "vehclNo", ed_eqCd.getValue());
            ds_retrieve.setCellData(0, "wrkCls", acb_workGubun.getValue());
            ds_retrieve.setCellData(0, "odrKnd", ed_odrNo.getValue());
            ds_retrieve.setCellData(0, "selConfirm", acb_selConfirm.getValue());
            ds_retrieve.setCellData(0, "dptWrkPlCd", ed_dptWrkPlCd.getValue());
            ds_retrieve.setCellData(0, "arvWrkPlCd", ed_arvWrkPlCd.getValue());
            ds_retrieve.setCellData(0, "bilgMchtCd", ed_bilgMchtCd.getValue());
            ds_retrieve.setCellData(0, "copCoCd", ed_copCoCd.getValue());
            ds_retrieve.setCellData(0, "dcScKnd", acb_dcScKnd.getValue());
            ds_retrieve.setCellData(0, "dcScAmtRate", ed_dcScAmtRate.getValue());

            let e = await $c.sbm.execute(sbm_deleteEmp);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_deleteEmp_submitdone(e);
            } 
        }
    } else {
        await $c.gus.cfAlertMsg("삭제할 자료가 없습니다.");
        return;
    }
};

scwin.f_CancelDcsn = function () {
    for (var i = 0; i < ds_emp.getRowCount(); i++) {
        if (ds_emp.getOriginalCellData(i, "regDtm") != ""  && ds_emp.getOriginalCellData(i, "dcsnYn") == "2") { 
            ds_emp.setCellData(i, "che", "1");
            ds_emp.setCellData(i, "dcsnYn", "0");
            ds_emp.setCellData(i, "dcsnDt", "");

            //20150209 지수, 확정해제시 confirmYn 2(미확인)으로 dtm null으로,
            ds_emp.setCellData(i, "confirmYn", "2");
            ds_emp.setCellData(i, "confirmDt", "");    
        }
    }
};

scwin.f_DcsnChoice = function () {
    if (scwin.cheCnt == "1") {
        ds_emp.undoAll(); 

        for (var i = 0; i < ds_emp.getRowCount(); i++) {
            ds_emp.setCellData(i, "che", "0"); 
            ds_emp.setCellData(i, "dcsnYn", ds_emp.getOriginalCellData(i,"dcsnYn"));
            ds_emp.setCellData(i, "dcsnDt", ds_emp.getOriginalCellData(i,"dcsnDt"));
        }

        scwin.cheCnt = "0";
    } else {
        for (var i = 0; i < ds_emp.getRowCount(); i++) {
            if (ds_emp.getOriginalCellData(i,"regDtm") != ""  && ds_emp.getOriginalCellData(i,"dcsnYn") != "2") {
                ds_emp.setCellData(i, "che", "1");
                ds_emp.setCellData(i, "dcsnYn", "2");

                if (ica_allCopCoConfirmDt.getValue() == "" ) {
                    ds_emp.setCellData(i, "dcsnDt", scwin.strFromDate);
                } else {
                    ds_emp.setCellData(i, "dcsnDt", ica_allCopCoConfirmDt.getValue());
                }
            }
        }
        scwin.cheCnt = "1"; 
    }
};

scwin.f_chkDptDt = function (wrkDt) {
    if (wrkDt == "St") {
        if (acb_dptGubun.getValue() != "") {
            ed_dptStDt.setValue(wrkStDt.getValue());                                                                                                                                                                                                                                                                             
            ed_dptEndDt.setValue(wrkEndDt.getValue()); 
        }
    } else if (wrkDt == "End") {
        if (acb_dptGubun.getValue() != "") {
            ed_dptStDt.setValue(wrkStDt.getValue());                                                                                                                                                                                                                                                                             
            ed_dptEndDt.setValue(wrkEndDt.getValue()); 
        }
    }
};

// 현재 화면에 표시되고 있는 활성화된 그리드 객체를 반환한다.
scwin.f_getActiveGrid = function() {
    // 순차적으로 체크하여 보이는 그리드를 리턴
    if (gr_emp.getStyle("display") !== "none")  return gr_emp;
    if (gr_emp2.getStyle("display") !== "none") return gr_emp2;
    if (gr_emp3.getStyle("display") !== "none") return gr_emp3;

    return null; // 모두 숨겨진 경우
};

scwin.f_filter = function () {
    ds_emp.clearFilter();

    let fn_tmpDeptFilter = function(cellData, tmpParam, rowIdx) {
        var temp = acb_wrkClsCd.getValue(); // 작업구간 value
        if (temp != "") {
            if (temp == "S") {
                temp = "셔틀";
            } else if (temp == "L") {
                temp = "로컬";
            } else if (temp == "J") {
                temp = "중장거리";
            }

            if (temp == "") {
                return true;
            }

            if (temp  == ds_emp.getCellData(rowIdx, "wrkClsCd")) {
                return true;
            } else {
                return false;
            }
        }

        var pusanClsCd = acb_pusanClsCd.getValue(); // 부산구간 value
        if (pusanClsCd != "") {
            if (pusanClsCd == "01") { // 감만권역
                if (ds_emp.getCellData(rowIdx, "dptDistrictCd") == "GMN" || ds_emp.getCellData(rowIdx, "arvDistrictCd") == "GMN") {
                    return true;
                } else {
                    return false;
                }        
            } else if (pusanClsCd == "02") { // 부두권역
                if (ds_emp.getCellData(rowIdx, "dptDistrictCd") == "JRB" || ds_emp.getCellData(rowIdx, "arvDistrictCd") == "JRB") {
                    return true;
                } else {
                    return false;
                } 
            } else if (pusanClsCd == "03") { // 감천부두
                if (ds_emp.getCellData(rowIdx, "dptDistrictCd") == "GCN" || ds_emp.getCellData(rowIdx, "arvDistrictCd") == "GCN") {
                    return true;
                }else{
                    return false;
                } 
            } else if (pusanClsCd == "04") { //신항권역
                if (ds_emp.getCellData(rowIdx, "dptDistrictCd") == "NEW_PORT" || ds_emp.getCellData(rowIdx, "arvDistrictCd") == "NEW_PORT") {
                    return true;
                } else {
                    return false;
                } 
            }
        }

        return true;
    }

    ds_emp.setColumnFilter({type: "func",  columnId: "wrkStpCd", key: fn_tmpDeptFilter, condition: "and"});

    totalRows.setValue(ds_emp.getRowCount());
};

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_joblevel_submitdone = function (e) {

    ds_joblevel.setJSON(e.responseJSON.GAUCE.sort((a, b) => {
        const valA = a.lobranNm || "";
        const valB = b.lobranNm || "";

        const isEngA = /^[a-zA-Z]/.test(valA);
        const isEngB = /^[a-zA-Z]/.test(valB);

        if (isEngA && !isEngB) return -1; 
        if (!isEngA && isEngB) return 1;

        return valA.localeCompare(valB, 'ko', { sensitivity: 'base' });
    }));

    var tmpRsData = ds_joblevel.getMatchedColumnData("lobranCd", scwin.sLobranCd, "lobranCd"); 
    if (tmpRsData != null) {
        if (tmpRsData.length > 0) {
            acb_logisticsBranch.setValue(scwin.sLobranCd);
        }
    } 
};

scwin.sbm_dcScKnd_submitdone = function (e) {
	ds_dcScKnd.insertRow(0);
