	ds_dcScKnd.insertRow(1);
    ds_dcScKnd.setCellData(1, "cd", "0001");
    ds_dcScKnd.setCellData(1, "cdNm", "전체");

    acb_workGubun.setValue("");

    $c.gus.cfCopyDataSet(ds_dcScKnd, ds_dcScKnd2, "copyHeader=Yes");
    acb_dcScKndBatch.setValue("");
};

