scwin.gr_emp_onheaderclick = function (headerId) {
    if (scwin.cheCnt == "1") { 
        ds_emp.undoAll(); 
        scwin.cheCnt = "0"; 
    } else {
        for (var i = 0; i < ds_emp.getRowCount(); i++) { 
            if ( ds_emp.getOriginalCellData(i, "regDtm") == "") { 
                ds_emp.setCellData(i, "che", "1"); 
            } 
        } 
        scwin.cheCnt = "1"; 
    } 
};

