scwin.gr_emp_oneditend = function (rowIndex, columnIndex, value) {
    var colid = gr_emp.getColumnID(columnIndex);
    switch (colid) {
        case "confirmYn" :
            if (ds_emp.getCellData(ds_emp.getRowPosition(), "confirmYn") == 0) {
                ds_emp.setCellData(ds_emp.getRowPosition(), "confirmDt", "");
            } else {
                ds_emp.setCellData(ds_emp.getRowPosition(), "confirmDt", scwin.strFromDate); 
            }

            if (ds_emp.getOriginalCellData(rowIndex, colid) != ds_emp.getCellData(rowIndex, colid)) { 
                ds_emp.setCellData(rowIndex, "che", 1); 
            } else {
                ds_emp.setCellData(rowIndex, "che", 0);
            }
        break;
        case "dcsnYn" :
            if (ds_emp.getCellData(ds_emp.getRowPosition(), "dcsnYn") == 0) {
                ds_emp.setCellData(ds_emp.getRowPosition(), "dcsnDt", "");
            } else {
                ds_emp.setCellData(ds_emp.getRowPosition(), "dcsnDt", scwin.strFromDate); 
            }

            if (ds_emp.getOriginalCellData(rowIndex, colid) != ds_emp.getCellData(rowIndex, colid)) {
                ds_emp.setCellData(rowIndex, "che", 1);
            } else {
                ds_emp.setCellData(rowIndex, "che", 0);
            }
        break;
        default :
        break;
    }
};

