    }
};

scwin.gr_emp3_onbeforecolumnmove = function (info) {
    const validArr = ["che", "odrNo"];
    const startColumnID = info.startColumnID;
    const endColumnID = info.endColumnID;
    if($.inArray(startColumnID, validArr) > -1) {
        return false;

    }
    if($.inArray(endColumnID, validArr) > -1) {
        return false;
    }
};
